1	<?php
2	
3	namespace App\Services;
4	
5	use App\Events\AdmisiQueueUpdated;
6	use App\Events\AntreanTvUpdated;
7	use App\Events\TriaseQueueUpdated;
8	use App\Models\DiagnosticOrder;
9	use App\Models\Prescription;
10	use App\Models\Queue;
11	use App\Models\SurgerySchedule;
12	use App\Models\SystemLog;
13	use App\Models\Visit;
14	use Illuminate\Database\Eloquent\Collection;
15	use Illuminate\Http\Request;
16	use Illuminate\Support\Facades\DB;
17	
18	/**
19	 * Sentral logic antrian — referensi: ARCHITECTURE.md Section 11 (Service Flow).
20	 *
21	 * Alur:  A → (TRIASE & REFRAKSIONIS paralel) → D → (P? / B?) → K → F → SELESAI
22	 *
23	 * Setiap "selesaiAntrian" memanggil advanceFromStation() yang:
24	 *   1. Tandai baris queues sekarang -> COMPLETED
25	 *   2. Tentukan station berikutnya (lihat resolveNextStation)
26	 *   3. Enqueue baris baru di station tujuan (atau set visit.current_station=SELESAI)
27	 *   4. Broadcast event Reverb yang relevan
28	 *
29	 * resolveNextStation kontrak:
30	 *   string         → enqueue baris baru di station itu
31	 *   array<string>  → enqueue multi paralel
32	 *   END_OF_FLOW    → pasien pulang (current_station=SELESAI)
33	 *   NO_OP          → tutup queue saja, no enqueue, current_station tetap (mis. partner TR sudah trigger next)
34	 *   null           → gate belum passed, antrian tidak boleh ditutup (throw)
35	 */
36	class QueueService
37	{
38	    public const END_OF_FLOW = '__END__';
39	    public const NO_OP       = '__NOOP__';
40	
41	    public function __construct(private readonly Request $request) {}
42	
43	    // =========================================================================
44	    // GENERATE NUMBER (thread-safe per station per hari)
45	    // =========================================================================
46	
47	    /**
48	     * Generate nomor antrian.
49	     *
50	     * Untuk station DOKTER, prefix bisa dynamic berdasarkan nomor ruangan:
51	     *   room="1" → prefix="D1", queue_number="D1-001"
52	     *   room="2" → prefix="D2", queue_number="D2-001"
53	     *   room=null → prefix="D",  queue_number="D-001"  (fallback)
54	     *
55	     * Sequence dihitung PER PREFIX per hari, sehingga D1 dan D2
56	     * punya counter terpisah (D1-001 dan D2-001 bisa exist bersamaan).
57	     */
58	    public function generateQueueNumber(string $station, ?string $room = null): array
59	    {
60	        if ($station === Queue::STATION_DOKTER && $room !== null && $room !== '') {
61	            $prefix = 'D' . $room;
62	
63	            $lastSeq = Queue::where('station', Queue::STATION_DOKTER)
64	                ->where('queue_prefix', $prefix)
65	                ->whereDate('created_at', today())
66	                ->max('queue_sequence') ?? 0;
67	
68	            $sequence = $lastSeq + 1;
69	        } else {
70	            $prefix = Queue::prefixFor($station);
71	
72	            // Stasiun yang share prefix (mis. TRIASE + REFRAKSIONIS = "TR")
73	            // perlu sequence yang juga shared supaya nomor tidak collision.
74	            $stationsForSeq = Queue::SHARED_PREFIX_GROUPS[$prefix] ?? [$station];
75	
76	            $lastSeq = Queue::whereIn('station', $stationsForSeq)
77	                ->whereDate('created_at', today())
78	                ->max('queue_sequence') ?? 0;
79	
80	            $sequence = $lastSeq + 1;
81	        }
82	
83	        return [
84	            'queue_prefix'   => $prefix,
85	            'queue_sequence' => $sequence,
86	            'queue_number'   => $prefix . '-' . str_pad($sequence, 3, '0', STR_PAD_LEFT),
87	        ];
88	    }
89	
90	    // =========================================================================
91	    // CORE ACTIONS
92	    // =========================================================================
93	
94	    /**
95	     * Buat antrian baru di station tertentu untuk sebuah visit.
96	     * Broadcast `added` ke channel `antrean-tv` agar TV langsung lihat row baru.
97	     *
98	     * Untuk station DOKTER, room diambil otomatis dari visit.doctorSchedule.room
99	     * sehingga queue_number menjadi "D{room}-xxx".
100	     *
101	     * @param  array|null  $sharedNumber  Optional: pakai nomor pre-generated
102	     *                                    (untuk pair TRIASE+REFRAKSIONIS yg share TR-NNN)
103	     */
104	    public function enqueue(string $visitId, string $station, ?array $sharedNumber = null): Queue
105	    {
106	        $this->assertStation($station);
107	
108	        if ($sharedNumber) {
109	            $data = $sharedNumber;
110	        } elseif ($station === Queue::STATION_DOKTER) {
111	            // Ambil ruangan dokter yang di-assign saat admisi
112	            $visit = \App\Models\Visit::with('doctorSchedule')->find($visitId);
113	            $room  = $visit?->doctorSchedule?->room;
114	            $data  = $this->generateQueueNumber($station, $room);
115	        } else {
116	            $data = $this->generateQueueNumber($station);
117	        }
118	
119	        $queue = Queue::create([
120	            'visit_id'       => $visitId,
121	            'station'        => $station,
122	            'queue_prefix'   => $data['queue_prefix'],
123	            'queue_sequence' => $data['queue_sequence'],
124	            'queue_number'   => $data['queue_number'],
125	            'status'         => Queue::STATUS_WAITING,
126	        ]);
127	
128	        $this->broadcastQueueUpdate($queue->fresh(['visit.patient']), 'added');
129	
130	        return $queue;
131	    }
132	
133	    /**
134	     * Data tiket Dokter (D-NNN) untuk sebuah visit — dipakai stasiun TR untuk
135	     * mencetak tiket lanjutan setelah gate Triase+Refraksionis lolos & antrian
136	     * DOKTER otomatis dibuat (lihat checkReadyForDoctor di Perawat/RefraksiService).
137	     * Return null kalau antrian DOKTER belum ada (partner TR belum finalize).
138	     */
139	    public function getDoctorTicket(string $visitId): ?array
140	    {
141	        $queue = Queue::byStation(Queue::STATION_DOKTER)
142	            ->where('visit_id', $visitId)
143	            ->whereDate('created_at', today())
144	            ->latest('created_at')
145	            ->first();
146	
147	        if (! $queue) {
148	            return null;
149	        }
150	
151	        $sched = Visit::with('doctorSchedule.employee')->find($visitId)?->doctorSchedule;
152	
153	        return [
154	            'queue_number' => $queue->queue_number,
155	            'poliklinik'   => $sched?->poliklinik,
156	            'room'         => $sched?->room,
157	            'doctor_name'  => $sched?->employee?->name,
158	        ];
159	    }
160	
161	    /**
162	     * Panggil antrian:
163	     *   - WAITING     → CALLED (panggilan awal)
164	     *   - CALLED      → CALLED (panggil ulang, pasien belum hadir/menjawab)
165	     *   - IN_PROGRESS → IN_PROGRESS (panggil ulang saat pasien sedang diperiksa,
166	     *                   mis. perlu kembali dari ruang ganti). Status tetap, hanya
167	     *                   `called_at` di-refresh + broadcast ulang ke speaker/TV.
168	     * COMPLETED/CANCELLED ditolak.
169	     */
170	    public function panggil(string $queueId): Queue
171	    {
172	        $queue = Queue::findOrFail($queueId);
173	
174	        // SELESAI_PENUNJANG (& DI_PENUNJANG) tetap bisa dipanggil — dokter melanjutkan pemeriksaan.
175	        $callable = array_merge(Queue::ACTIVE_STATUSES, [Queue::STATUS_AT_PENUNJANG, Queue::STATUS_PENUNJANG_DONE]);
176	        if (! in_array($queue->status, $callable, true)) {
177	            throw new \Exception('Antrian sudah selesai atau dibatalkan — tidak bisa dipanggil.', 422);
178	        }
179	
180	        $queue->update([
181	            'status'    => $queue->status === Queue::STATUS_IN_PROGRESS
182	                ? Queue::STATUS_IN_PROGRESS   // pertahankan IN_PROGRESS saat re-call
183	                : Queue::STATUS_CALLED,
184	            'called_at' => now(),
185	        ]);
186	
187	        $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
188	
189	        return $queue->fresh(['visit.patient']);
190	    }
191	
192	    /**
193	     * Mulai layanan: CALLED -> IN_PROGRESS.
194	     */
195	    public function mulai(string $queueId): Queue
196	    {
197	        $queue = Queue::findOrFail($queueId);
198	
199	        if ($queue->status !== Queue::STATUS_CALLED) {
200	            throw new \Exception('Panggil pasien terlebih dahulu.', 422);
201	        }
202	
203	        $queue->update([
204	            'status'     => Queue::STATUS_IN_PROGRESS,
205	            'started_at' => now(),
206	        ]);
207	
208	        $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
209	
210	        return $queue->fresh(['visit.patient']);
211	    }
212	
213	    /**
214	     * Lewati / skip pasien: turunkan SATU posisi — tukar urutan dengan pasien
215	     * berikutnya yang masih aktif (WAITING/CALLED) di station yang sama. Bila
216	     * pasien ini sudah paling bawah (tak ada yang aktif di bawahnya), tetap di
217	     * tempat (no-op posisi). Status selalu di-reset ke WAITING (kalau tadinya
218	     * CALLED, panggilannya dibatalkan).
219	     */
220	    public function lewati(string $queueId): Queue
221	    {
222	        return DB::transaction(function () use ($queueId) {
223	            $queue = Queue::whereIn('status', [Queue::STATUS_WAITING, Queue::STATUS_CALLED])
224	                ->lockForUpdate()
225	                ->findOrFail($queueId);
226	
227	            // Pasien berikutnya = baris aktif dengan queue_sequence terkecil yang
228	            // masih lebih besar dari baris ini (kandidat layanan setelah ini).
229	            $next = Queue::byStation($queue->station)
230	                ->whereDate('created_at', today())
231	                ->whereIn('status', [Queue::STATUS_WAITING, Queue::STATUS_CALLED])
232	                ->where('id', '!=', $queue->id)
233	                ->where('queue_sequence', '>', $queue->queue_sequence)
234	                ->orderBy('queue_sequence')
235	                ->lockForUpdate()
236	                ->first();
237	
238	            if ($next) {
239	                // Tukar urutan: pasien ini turun 1, pasien berikutnya naik 1.
240	                $thisSeq = $queue->queue_sequence;
241	                $nextSeq = $next->queue_sequence;
242	                $next->update(['queue_sequence' => $thisSeq]);
243	                $queue->update([
244	                    'queue_sequence' => $nextSeq,
245	                    'status'         => Queue::STATUS_WAITING,
246	                    'called_at'      => null,
247	                ]);
248	                $this->broadcastQueueUpdate($next->fresh(['visit.patient']));
249	            } else {
250	                // Sudah paling bawah — cuma reset status (batalkan panggilan bila CALLED).
251	                $queue->update([
252	                    'status'    => Queue::STATUS_WAITING,
253	                    'called_at' => null,
254	                ]);
255	            }
256	
257	            $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
258	
259	            return $queue->fresh(['visit.patient']);
260	        });
261	    }
262	
263	    /**
264	     * Batal: status -> CANCELLED. Tidak buat antrian baru.
265	     */
266	    public function batal(string $queueId, ?string $reason = null): Queue
267	    {
268	        $queue = Queue::findOrFail($queueId);
269	
270	        $queue->update([
271	            'status'       => Queue::STATUS_CANCELLED,
272	            'completed_at' => now(),
273	        ]);
274	
275	        $this->log(auth('api')->id(), 'CANCEL_ANTRIAN', Queue::class, $queueId, $reason);
276	        $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
277	
278	        return $queue->fresh(['visit.patient']);
279	    }
280	
281	    // =========================================================================
282	    // ADVANCE (selesaiAntrian per station) — Section 11.3
283	    // =========================================================================
284	
285	    /**
286	     * Tandai antrian COMPLETED + buat antrian baru di station berikutnya
287	     * berdasarkan aturan transisi Section 11.3.
288	     *
289	     * @return array{queue: Queue, visit: Visit, next_station: ?string, next_queue: ?Queue}
290	     */
291	    public function advanceFromStation(string $queueId, string $expectedStation): array
292	    {
293	        $result = DB::transaction(function () use ($queueId, $expectedStation) {
294	            $queue = Queue::with('visit')->findOrFail($queueId);
295	
296	            if ($queue->station !== $expectedStation) {
297	                throw new \Exception(
298	                    "Station antrian tidak cocok: expected={$expectedStation}, actual={$queue->station}.",
299	                    422
300	                );
301	            }
302	
303	            if ($queue->status === Queue::STATUS_COMPLETED) {
304	                throw new \Exception('Antrian sudah ditutup.', 422);
305	            }
306	
307	            // 1. Resolve next station SEBELUM close — bisa throw kalau gate belum passed
308	            $visit       = $queue->visit;
309	            $nextStation = $this->resolveNextStation($visit, $expectedStation);
310	
311	            if ($nextStation === null) {
312	                throw new \Exception(
313	                    "Antrian {$expectedStation} belum bisa diselesaikan — sub-task belum lengkap.",
314	                    422
315	                );
316	            }
317	
318	            // 2. Close current queue
319	            $queue->update([
320	                'status'       => Queue::STATUS_COMPLETED,
321	                'completed_at' => now(),
322	            ]);
323	
324	            // 3. Enqueue next / END_OF_FLOW
325	            $nextQueue       = null;
326	            $nextStationName = null;
327	
328	            if ($nextStation === self::END_OF_FLOW) {
329	                $visit->update(['current_station' => 'SELESAI']);
330	                $nextStationName = 'SELESAI';
331	            } elseif ($nextStation === self::NO_OP) {
332	                $nextStationName = 'NO_OP';
333	            } elseif (is_array($nextStation)) {
334	                // Cek apakah semua station di array share prefix yang sama
335	                // (mis. [TRIASE, REFRAKSIONIS] → keduanya prefix "TR"). Kalau iya,
336	                // generate SATU nomor antrean dan terapkan ke semua baris.
337	                $prefixes = array_unique(array_map(fn ($s) => Queue::prefixFor($s), $nextStation));
338	                $shared   = count($prefixes) === 1 ? $this->generateQueueNumber($nextStation[0]) : null;
339	
340	                foreach ($nextStation as $st) {
341	                    $this->enqueue($visit->id, $st, $shared);
342	                }
343	
344	                $visit->update(['current_station' => $nextStation[0]]);
345	                $nextStationName = implode('+', $nextStation);
346	            } else {
347	                $nextQueue = $this->enqueue($visit->id, $nextStation);
348	                $visit->update(['current_station' => $nextStation]);
349	                $nextStationName = $nextStation;
350	            }
351	
352	            $this->log(
353	                auth('api')->id(),
354	                'ADVANCE_QUEUE',
355	                Visit::class,
356	                $visit->id,
357	                "Selesai {$expectedStation} → {$nextStationName}"
358	            );
359	
360	            $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
361	
362	            return [
363	                'queue'        => $queue->fresh(['visit.patient']),
364	                'visit'        => $visit->fresh(['patient', 'queues']),
365	                'next_station' => $nextStationName,
366	                'next_queue'   => $nextQueue,
367	            ];
368	        });
369	
370	        // Lapor waktu antrean ke BPJS SETELAH commit (post-transaction) — non-blocking:
371	        // kegagalan/timeout/credential-kosong tidak boleh membatalkan transisi lokal.
372	        $this->reportAntreanWaktu($result['visit'] ?? null, $expectedStation, $result['next_station'] ?? null);
373	
374	        return $result;
375	    }
376	
377	    /**
378	     * Kirim updatewaktu ke BPJS Antrean untuk kunjungan BPJS yang punya kode booking.
379	     * taskid BPJS dipetakan dari station: DOKTER mulai=3/selesai=4, FARMASI mulai=5/selesai=6.
380	     * Selalu dibungkus try/catch + hanya jika ANTREAN aktif — TIDAK pernah melempar.
381	     */
382	    private function reportAntreanWaktu(?Visit $visit, string $fromStation, ?string $nextStation): void
383	    {
384	        try {
385	            if (! $visit || $visit->guarantor_type !== 'BPJS' || empty($visit->bpjs_booking_code)) {
386	                return;
387	            }
388	
389	            $antrean = app(\App\Services\BpjsAntreanService::class);
390	            if (! $antrean->isEnabled()) {
391	                return;
392	            }
393	
394	            // Pemetaan taskid: selesai di station = lapor task selesai station tsb.
395	            $taskMap = [
396	                'DOKTER'  => 4, // selesai layan poli
397	                'FARMASI' => 6, // selesai farmasi
398	                'KASIR'   => 7, // selesai (pulang)
399	            ];
400	            $taskId = $taskMap[$fromStation] ?? null;
401	            if ($taskId === null) {
402	                return; // station lain (ADMISI/TRIASE/dll) tidak wajib lapor per BPJS
403	            }
404	
405	            $antrean->updateWaktuAntrean([
406	                'kodebooking' => $visit->bpjs_booking_code,
407	                'taskid'      => $taskId,
408	                'waktu'       => (int) (microtime(true) * 1000),
409	            ], $visit->id);
410	        } catch (\Throwable $e) {
411	            // Diam-diam — sudah tercatat di bpjs_antrean_logs lewat service; jangan ganggu flow.
412	            \Illuminate\Support\Facades\Log::warning('BPJS updatewaktu gagal: ' . $e->getMessage());
413	        }
414	    }
415	
416	    /**
417	     * Tentukan station berikutnya berdasarkan kondisi visit + aturan Section 11.3.
418	     *
419	     * Return: string | array | null
420	     *   - string  : single next station
421	     *   - array   : multi parallel (mis. [TRIASE, REFRAKSIONIS])
422	     *   - null    : pasien pulang (SELESAI)
423	     */
424	    public function resolveNextStation(Visit $visit, string $fromStation): string|array|null
425	    {
426	        return match ($fromStation) {
427	            Queue::STATION_ADMISI       => [Queue::STATION_TRIASE, Queue::STATION_REFRAKSIONIS],
428	            Queue::STATION_TRIASE       => $this->nextAfterTriaseOrRefraksi($visit),
429	            Queue::STATION_REFRAKSIONIS => $this->nextAfterTriaseOrRefraksi($visit),
430	            Queue::STATION_DOKTER       => $this->nextAfterDokter($visit),
431	            Queue::STATION_PENUNJANG    => $this->nextAfterPenunjang($visit), // balik ke dokter (anti-duplikat)
432	            Queue::STATION_BEDAH        => Queue::STATION_KASIR,
433	            Queue::STATION_KASIR        => $this->nextAfterKasir($visit),
434	            Queue::STATION_FARMASI      => self::END_OF_FLOW, // pasien pulang
435	            default                     => null,
436	        };
437	    }
438	
439	    /**
440	     * TRIASE atau REFRAKSIONIS selesai → DOKTER hanya jika keduanya sudah finalize.
441	     * Jika belum, tetap di station yg sama (return null = jangan enqueue baru).
442	     *
443	     * Khusus visit PREOP_BEDAH: gate paralel sama (TR+REF wajib selesai), tapi
444	     * transisi ke BEDAH dilakukan eksplisit lewat PerawatService::kirimKeBedah()
445	     * (tombol manual). Auto-advance dimatikan untuk mencegah pasien tidak sengaja
446	     * didorong ke bedah hanya karena finalize asesmen.
447	     */
448	    private function nextAfterTriaseOrRefraksi(Visit $visit): ?string
449	    {
450	        $visit->loadMissing(['nurseAssessment', 'refractionRecord']);
451	
452	        $triaseDone   = (bool) $visit->nurseAssessment?->is_finalized;
453	        $refraksiDone = (bool) $visit->refractionRecord?->is_finalized;
454	
455	        if (! $triaseDone || ! $refraksiDone) {
456	            // Gate belum passed — antrian tidak boleh ditutup
457	            return null;
458	        }
459	
460	        // PREOP_BEDAH: jangan auto-advance — tunggu tombol "Kirim ke Bedah".
461	        // Sub-task lain (mis. refraksi finalize duluan) tetap NO_OP saat partner
462	        // sudah selesai supaya antrean asal boleh ditutup.
463	        if ($visit->visit_type === 'PREOP_BEDAH') {
464	            return self::NO_OP;
465	        }
466	
467	        // Partner (sub-task lain) sudah trigger transisi ke DOKTER → tutup saja, no-op
468	        $alreadyQueued = Queue::byStation(Queue::STATION_DOKTER)
469	            ->where('visit_id', $visit->id)
470	            ->today()
471	            ->exists();
472	
473	        return $alreadyQueued ? self::NO_OP : Queue::STATION_DOKTER;
474	    }
475	
476	    /**
477	     * DOKTER selesai → urutan prioritas:
478	     *   1. Ada DiagnosticOrder REQUESTED/IN_PROGRESS → PENUNJANG
479	     *   2. Planning BEDAH dengan jadwal operasi HARI INI → BEDAH
480	     *      (planning BEDAH dengan jadwal hari lain → tetap lanjut ke KASIR;
481	     *       saat hari operasi tiba pasien daftar ulang dari ADMISI)
482	     *   3. Else → KASIR
483	     */
484	    private function nextAfterDokter(Visit $visit): string
485	    {
486	        // 1. Order penunjang yang masih open?
487	        $hasOpenOrder = DiagnosticOrder::where('visit_id', $visit->id)
488	            ->whereIn('status', ['REQUESTED', 'IN_PROGRESS'])
489	            ->exists();
490	
491	        if ($hasOpenOrder) {
492	            return Queue::STATION_PENUNJANG;
493	        }
494	
495	        // 2. Surgery schedule HARI INI?
496	        $visit->loadMissing('doctorExamination');
497	        $exam = $visit->doctorExamination;
498	
499	        if ($exam && $exam->planning === 'BEDAH' && $exam->surgery_schedule_id) {
500	            $isToday = SurgerySchedule::where('id', $exam->surgery_schedule_id)
501	                ->whereDate('scheduled_date', today())
502	                ->whereIn('status', ['SCHEDULED', 'IN_PROGRESS'])
503	                ->exists();
504	
505	            if ($isToday) {
506	                return Queue::STATION_BEDAH;
507	            }
508	            // Jadwal hari lain → pasien pulang via KASIR & FARMASI, kembali di hari operasi.
509	        }
510	
511	        // 3. Default
512	        return Queue::STATION_KASIR;
513	    }
514	
515	    /**
516	     * PENUNJANG selesai → balik ke DOKTER. Tapi bila baris DOKTER pasien masih hidup
517	     * (di-pause saat dikirim ke penunjang), jangan buat baris baru — PenunjangService
518	     * ::requeueToDokter yang menaikkannya kembali. NO_OP mencegah duplikat.
519	     */
520	    private function nextAfterPenunjang(Visit $visit): string
521	    {
522	        $hasLiveDokter = Queue::byStation(Queue::STATION_DOKTER)
523	            ->where('visit_id', $visit->id)
524	            ->today()
525	            ->whereNotIn('status', [Queue::STATUS_COMPLETED, Queue::STATUS_CANCELLED])
526	            ->exists();
527	
528	        return $hasLiveDokter ? self::NO_OP : Queue::STATION_DOKTER;
529	    }
530	
531	    /**
532	     * KASIR selesai → FARMASI jika ada resep, else SELESAI.
533	     */
534	    private function nextAfterKasir(Visit $visit): string
535	    {
536	        $hasPrescription = Prescription::where('visit_id', $visit->id)
537	            ->whereIn('status', ['DRAFT', 'SUBMITTED', 'DISPENSING'])
538	            ->exists();
539	
540	        return $hasPrescription ? Queue::STATION_FARMASI : self::END_OF_FLOW;
541	    }
542	
543	    // =========================================================================
544	    // QUERY HELPERS
545	    // =========================================================================
546	
547	    public function getByStation(string $station): Collection
548	    {
549	        $this->assertStation($station);
550	
551	        return Queue::with(['visit.patient'])
552	            ->byStation($station)
553	            ->today()
554	            ->orderBy('queue_sequence')
555	            ->get();
556	    }
557	
558	    /**
559	     * Snapshot semua antrean aktif per station — untuk Antrean TV / Dashboard.
560	     */
561	    public function getAllActive(): array
562	    {
563	        $result = [];
564	
565	        foreach (Queue::STATIONS as $station) {
566	            $rows = Queue::with(['visit.patient'])
567	                ->byStation($station)
568	                ->today()
569	                ->orderBy('queue_sequence')
570	                ->get();
571	
572	            $called = $rows->firstWhere('status', Queue::STATUS_CALLED);
573	            $next   = $rows->firstWhere('status', Queue::STATUS_WAITING);
574	
575	            $result[$station] = [
576	                'prefix'   => Queue::prefixFor($station),
577	                'total'    => $rows->count(),
578	                'waiting'  => $rows->where('status', Queue::STATUS_WAITING)->count(),
579	                'called'   => $called ? $this->formatLite($called) : null,
580	                'next'     => $next ? $this->formatLite($next) : null,
581	                'rows'     => $rows->map(fn ($r) => $this->formatLite($r))->values(),
582	            ];
583	        }
584	
585	        return $result;
586	    }
587	
588	    public function getStatus(string $queueId): Queue
589	    {
590	        return Queue::with(['visit.patient'])->findOrFail($queueId);
591	    }
