593	    // =========================================================================
594	    // PRIVATE
595	    // =========================================================================
596	
597	    private function assertStation(string $station): void
598	    {
599	        if (! in_array($station, Queue::STATIONS, true)) {
600	            throw new \Exception("Station tidak dikenal: {$station}.", 422);
601	        }
602	    }
603	
604	    private function broadcastQueueUpdate(Queue $queue, string $action = 'updated'): void
605	    {
606	        $payload = [
607	            'id'             => $queue->id,
608	            'visit_id'       => $queue->visit_id,
609	            'station'        => $queue->station,
610	            'queue_number'   => $queue->queue_number,
611	            'queue_sequence' => $queue->queue_sequence,
612	            'status'         => $queue->status,
613	            'called_at'      => $queue->called_at?->toIso8601String(),
614	            'patient'        => $queue->visit?->patient ? [
615	                'no_rm' => $queue->visit->patient->no_rm,
616	                'name'  => $queue->visit->patient->name,
617	            ] : null,
618	        ];
619	
620	        // Per-station channel — dipakai view modul masing-masing (AdmisiView, PerawatView, RefraksionisView)
621	        match ($queue->station) {
622	            Queue::STATION_ADMISI => broadcast(new AdmisiQueueUpdated($payload, $action))->toOthers(),
623	            Queue::STATION_TRIASE, Queue::STATION_REFRAKSIONIS
624	                => broadcast(new TriaseQueueUpdated($payload, $action))->toOthers(),
625	            default => null, // station lain (D/P/B/K/F) belum punya event station-specific
626	        };
627	
628	        // Generic channel untuk Antrean TV — fire untuk SEMUA station termasuk
629	        // DOKTER, PENUNJANG, BEDAH, KASIR, FARMASI agar TV update real-time.
630	        broadcast(new AntreanTvUpdated($payload, $action))->toOthers();
631	    }
