636	            'id'             => $q->id,
637	            'queue_number'   => $q->queue_number,
638	            'queue_sequence' => $q->queue_sequence,
639	            'status'         => $q->status,
640	            'visit_id'       => $q->visit_id,
641	            'patient_name'   => $q->visit?->patient?->name,
642	            'no_rm'          => $q->visit?->patient?->no_rm,
643	            'called_at'      => $q->called_at?->toIso8601String(),
644	        ];
645	    }
646	
647	    private function log(
648	        ?string $userId,
649	        string $action,
650	        ?string $model = null,
651	        ?string $modelId = null,
652	        ?string $description = null
653	    ): void {
654	        SystemLog::create([
655	            'user_id'     => $userId,
656	            'action'      => $action,
657	            'model'       => $model,
658	            'model_id'    => $modelId,
659	            'description' => $description,
660	            'ip_address'  => $this->request->ip(),
661	            'user_agent'  => $this->request->userAgent(),
662	        ]);
663	    }
664	}
