137	    /**
138	     * Build invoice from all visit sources: tindakan, obat, IOL (bedah), registrasi.
139	     * Applies tariff lookup with fallback logic.
140	     * Applies COB if configured.
141	     */
142	    public function consolidateBilling(string $visitId): BillingInvoice
143	    {
144	        $visit = Visit::with([
145	            'patient',
146	            'visitServices.procedure',
147	            'prescriptions.items.medication',
148	            'diagnosticOrders',
149	            'doctorExamination.surgerySchedule.surgeryRecord.iolUsages.iolItem',
150	            'doctorExamination.surgeryPackage.items',
151	            'surgeryRequests.bhpItems.bhpItem',
152	            'equipmentUsages.equipment',
153	            'visitCob.penjamin1',
154	            'visitCob.penjamin2',
155	        ])->findOrFail($visitId);
156	
157	        if (BillingInvoice::where('visit_id', $visitId)->whereNotIn('status', ['CANCELLED'])->exists()) {
158	            throw new \Exception('Invoice sudah ada untuk kunjungan ini.', 422);
159	        }
160	
161	        return DB::transaction(function () use ($visit) {
162	            // Builder pipeline — tiap source berdiri sendiri, return array baris BillingItem.
163	            // Tambah source baru = tambah satu method + tambah ke array_merge.
164	            $lines = array_merge(
165	                $this->buildRegistrasiLines($visit),
166	                $this->buildTindakanLines($visit),
167	                $this->buildObatLines($visit),
168	                $this->buildPenunjangLines($visit),
169	                $this->buildBhpLines($visit),
170	                $this->buildPaketRoomBhpLines($visit),
171	                $this->buildIolLines($visit),
172	                $this->buildEquipmentLines($visit),
173	            );
174	
175	            $subtotal = array_sum(array_map(fn ($l) => (float) ($l['total_price'] ?? 0), $lines));
176	
177	            // COB → global discount
178	            $discount = $this->calculateCOBDiscount($subtotal, $visit->visitCob);
179	            $total    = max(0, $subtotal - $discount);
180	
181	            $invoiceNumber = $this->generateInvoiceNumber();
182	
183	            $invoice = BillingInvoice::create([
184	                'visit_id'       => $visit->id,
185	                'invoice_number' => $invoiceNumber,
186	                'subtotal'       => $subtotal,
187	                'discount'       => $discount,
188	                'tax'            => 0,
189	                'total'          => $total,
190	                'status'         => 'DRAFT',
191	            ]);
192	
193	            foreach ($lines as $line) {
194	                BillingItem::create(array_merge($line, ['billing_invoice_id' => $invoice->id]));
195	            }
196	
197	            $this->log(auth('api')->id(), 'CONSOLIDATE_BILLING', BillingInvoice::class, $invoice->id, "Invoice {$invoiceNumber} — total {$total}");
198	
199	            return $invoice->load(['items', 'visit.patient']);
200	        });
201	    }
