636	    public function processPayment(string $invoiceId, array $data): BillingInvoice
637	    {
638	        $invoice = BillingInvoice::with('visit')->findOrFail($invoiceId);
639	
640	        if (! in_array($invoice->status, ['FINALIZED', 'PARTIALLY_PAID'])) {
641	            throw new \Exception('Invoice harus dalam status FINALIZED atau PARTIALLY_PAID untuk diproses.', 422);
642	        }
643	
644	        $paidAmount = (float) $data['paid_amount'];
645	
646	        if ($paidAmount <= 0) {
647	            throw new \Exception('Nominal bayar harus lebih dari 0.', 422);
648	        }
649	
650	        $user = auth('api')->user();
651	
652	        $fresh = DB::transaction(function () use ($invoice, $data, $paidAmount, $user) {
653	            $totalPaid   = $invoice->paid_amount + $paidAmount;
654	            // Tagihan dianggap lunas bila pembayaran pasien + porsi ditanggung asuransi
655	            // (covered_amount) sudah menutup total. Untuk pasien umum covered = 0.
656	            $isFullyPaid = ($totalPaid + (float) $invoice->covered_amount) >= $invoice->total;
657	
658	            $invoice->update([
659	                'paid_amount'    => $totalPaid,
660	                'payment_method' => $data['payment_method'],
661	                'status'         => $isFullyPaid ? 'PAID' : 'PARTIALLY_PAID',
662	                'paid_at'        => $isFullyPaid ? now() : $invoice->paid_at,
663	                'cashier_id'     => $user->employee_id,
664	                'notes'          => $data['notes'] ?? $invoice->notes,
665	            ]);
666	
667	            if ($isFullyPaid) {
668	                // Delegate ke QueueService::advanceFromStation supaya routing FARMASI vs SELESAI
669	                // di-handle satu tempat (nextAfterKasir cek prescription DRAFT/SUBMITTED/DISPENSING)
670	                // + TV broadcast jalan benar.
671	                $kasirQueue = Queue::where('visit_id', $invoice->visit_id)
672	                    ->where('station', 'KASIR')
673	                    ->whereIn('status', ['WAITING', 'CALLED', 'IN_PROGRESS'])
674	                    ->first();
675	                if ($kasirQueue) {
676	                    $this->queueService->advanceFromStation($kasirQueue->id, Queue::STATION_KASIR);
677	                } else {
678	                    // Tidak ada queue KASIR aktif (pasien dibayar dari non-queue flow) — set manual.
679	                    $invoice->visit->update(['current_station' => 'SELESAI']);
680	                }
681	
682	                // Auto-draft klaim TPA non-BPJS jika visit guarantor ASURANSI/PERUSAHAAN
683	                // dan sudah VERIFIED. BPJS punya alurnya sendiri (KlaimService), tidak disentuh.
684	                $this->maybeCreateInsuranceClaimDraft($invoice);
685	            }
686	
687	            $this->log(
688	                $user->id,
689	                'PROCESS_PAYMENT',
690	                BillingInvoice::class,
691	                $invoice->id,
692	                "Bayar {$paidAmount} via {$data['payment_method']} — status: " . ($isFullyPaid ? 'PAID' : 'PARTIALLY_PAID')
693	            );
694	
695	            return $invoice->fresh(['items', 'visit.patient', 'cashier']);
696	        });
697	
698	        // LPK BPJS post-commit (non-blocking): kirim Lembar Pengajuan Klaim ke VClaim
699	        // saat kunjungan BPJS lunas & punya SEP. Gagal/credential-kosong tidak ganggu.
700	        if ($fresh->status === 'PAID') {
701	            $this->maybeSubmitLpkBpjs($fresh->visit_id);
702	        }
703	
704	        return $fresh;
705	    }
