770	    /**
771	     * Konfirmasi tagihan yang DITANGGUNG PENUH asuransi/TPA — pasien tidak membayar.
772	     * Kasir hanya menekan "Konfirmasi". Invoice ditandai PAID dengan payment_method
773	     * INSURANCE, paid_amount tetap 0, covered_amount = total. Pendapatan asuransi
774	     * tetap terpisah dari pendapatan tunai pada laporan.
775	     */
776	    public function confirmInsuranceCoverage(string $invoiceId, array $data = []): BillingInvoice
777	    {
778	        $invoice = BillingInvoice::with('visit')->findOrFail($invoiceId);
779	
780	        if (! in_array($invoice->status, ['FINALIZED', 'PARTIALLY_PAID'])) {
781	            throw new \Exception('Invoice harus dalam status FINALIZED atau PARTIALLY_PAID untuk dikonfirmasi.', 422);
782	        }
783	
784	        // Sisa yang harus ditanggung pasien setelah cover & pembayaran sebelumnya.
785	        $patientDue = (float) $invoice->total - (float) $invoice->covered_amount - (float) $invoice->paid_amount;
786	        if ($patientDue > 0.009) {
787	            throw new \Exception(
788	                'Masih ada sisa Rp ' . number_format($patientDue, 0, ',', '.') . ' yang harus dibayar pasien. Gunakan proses pembayaran biasa.',
789	                422
790	            );
791	        }
792	
793	        $user = auth('api')->user();
794	
795	        return DB::transaction(function () use ($invoice, $data, $user) {
796	            // covered_amount minimal harus menutup total (full cover). Naikkan bila perlu.
797	            $covered = max((float) $invoice->covered_amount, (float) $invoice->total - (float) $invoice->paid_amount);
798	
799	            $invoice->update([
800	                'covered_amount' => $covered,
801	                'covered_by'     => $user->id,
802	                'covered_at'     => $invoice->covered_at ?? now(),
803	                'payment_method' => 'INSURANCE',
804	                'status'         => 'PAID',
805	                'paid_at'        => now(),
806	                'cashier_id'     => $user->employee_id,
807	                'notes'          => $data['notes'] ?? $invoice->notes,
808	            ]);
809	
810	            $kasirQueue = Queue::where('visit_id', $invoice->visit_id)
811	                ->where('station', 'KASIR')
812	                ->whereIn('status', ['WAITING', 'CALLED', 'IN_PROGRESS'])
813	                ->first();
814	            if ($kasirQueue) {
815	                $this->queueService->advanceFromStation($kasirQueue->id, Queue::STATION_KASIR);
816	            } else {
817	                $invoice->visit->update(['current_station' => 'SELESAI']);
818	            }
819	
820	            $this->maybeCreateInsuranceClaimDraft($invoice);
821	
822	            $this->log(
823	                $user->id,
824	                'CONFIRM_INSURANCE_COVERAGE',
825	                BillingInvoice::class,
826	                $invoice->id,
827	                "Ditanggung asuransi Rp {$covered} — status: PAID (INSURANCE)"
828	            );
829	
830	            return $invoice->fresh(['items', 'visit.patient', 'cashier']);
831	        });
832	    }
