834	    /**
835	     * Konfirmasi kunjungan BPJS — pasien TIDAK membayar di kasir. Tagihan
836	     * diselesaikan via klaim INA-CBG (alur KlaimService terpisah), bukan
837	     * pembayaran tunai. Kasir hanya menekan "Konfirmasi". Invoice ditandai
838	     * PAID dengan payment_method BPJS, paid_amount = 0 (tidak menambah kas).
839	     *
840	     * BEDA dgn confirmInsuranceCoverage: TIDAK set covered_amount dan TIDAK
841	     * membuat draft klaim TPA (BPJS punya jalur klaim sendiri).
842	     */
843	    public function confirmBpjsCoverage(string $invoiceId, array $data = []): BillingInvoice
844	    {
845	        $invoice = BillingInvoice::with('visit')->findOrFail($invoiceId);
846	
847	        if ($invoice->status === 'PAID' || $invoice->status === 'CANCELLED') {
848	            throw new \Exception('Invoice sudah lunas atau dibatalkan.', 422);
849	        }
850	
851	        $guarantor = strtoupper((string) ($invoice->visit?->guarantor_type ?? ''));
852	        if ($guarantor !== 'BPJS') {
853	            throw new \Exception('Konfirmasi BPJS hanya untuk kunjungan dengan penjamin BPJS.', 422);
854	        }
855	
856	        $user = auth('api')->user();
857	
858	        return DB::transaction(function () use ($invoice, $data, $user) {
859	            // Finalize dulu kalau masih DRAFT (kasir konfirmasi langsung tanpa step terpisah).
860	            if ($invoice->status === 'DRAFT') {
861	                $invoice->update(['status' => 'FINALIZED']);
862	            }
863	
864	            $invoice->update([
865	                'payment_method' => 'BPJS',
866	                'status'         => 'PAID',
867	                'paid_amount'    => 0,
868	                'paid_at'        => now(),
869	                'cashier_id'     => $user->employee_id,
870	                'notes'          => $data['notes'] ?? $invoice->notes,
871	            ]);
872	
873	            $kasirQueue = Queue::where('visit_id', $invoice->visit_id)
874	                ->where('station', 'KASIR')
875	                ->whereIn('status', ['WAITING', 'CALLED', 'IN_PROGRESS'])
876	                ->first();
877	            if ($kasirQueue) {
878	                $this->queueService->advanceFromStation($kasirQueue->id, Queue::STATION_KASIR);
879	            } else {
880	                $invoice->visit->update(['current_station' => 'SELESAI']);
881	            }
882	
883	            $this->log(
884	                $user->id,
885	                'CONFIRM_BPJS_COVERAGE',
886	                BillingInvoice::class,
887	                $invoice->id,
888	                "Kunjungan BPJS dikonfirmasi — status: PAID (BPJS), ditagih via klaim INA-CBG"
889	            );
890	
891	            return $invoice->fresh(['items', 'visit.patient', 'cashier']);
892	        });
893	    }
