933	    /**
934	     * Hitung pasangan (discount_amount, discount_percent) untuk satu baris.
935	     * Bila amount diisi → percent dihitung. Bila percent diisi → amount dihitung.
936	     * Bila keduanya kosong → 0/0.
937	     */
938	    private function computeItemDiscount(float $totalPrice, $amount, $percent): array
939	    {
940	        if (! is_null($amount)) {
941	            $amt = max(0, min((float) $amount, $totalPrice));
942	            $pc  = $totalPrice > 0 ? round($amt / $totalPrice * 100, 2) : 0;
943	            return [$amt, $pc];
944	        }
945	        if (! is_null($percent)) {
946	            $pc  = max(0, min((float) $percent, 100));
947	            $amt = round($totalPrice * $pc / 100, 2);
948	            return [$amt, $pc];
949	        }
950	        return [0.0, 0.0];
951	    }
952	
953	    public function updateItemInvoice(string $id, array $data): BillingItem
954	    {
955	        $item    = BillingItem::with('billingInvoice')->findOrFail($id);
956	        $invoice = $item->billingInvoice;
957	
958	        if (in_array($invoice->status, ['PAID', 'CANCELLED'])) {
959	            throw new \Exception('Invoice sudah final, tidak bisa ubah item.', 422);
960	        }
961	
962	        $qty        = $data['quantity'] ?? $item->quantity;
963	        $unitPrice  = $data['unit_price'] ?? $item->unit_price;
964	        $totalPrice = $unitPrice * $qty;
965	
966	        // Diskon: jika field dikirim → recompute. Kalau kedua field tidak ada di payload, pertahankan existing.
967	        $hasDisc = array_key_exists('discount_amount', $data) || array_key_exists('discount_percent', $data);
968	        if ($hasDisc) {
969	            [$discAmt, $discPc] = $this->computeItemDiscount(
970	                $totalPrice,
971	                $data['discount_amount']  ?? null,
972	                $data['discount_percent'] ?? null,
973	            );
974	        } else {
975	            // qty/unit_price berubah → jaga konsistensi: pakai persen lama.
976	            $pc      = (float) $item->discount_percent;
977	            $discAmt = round($totalPrice * $pc / 100, 2);
978	            $discPc  = $pc;
979	        }
980	        $netPrice = max(0, $totalPrice - $discAmt);
981	
982	        $item->update([
983	            'description'      => $data['description'] ?? $item->description,
984	            'category'         => array_key_exists('category', $data) ? $data['category'] : $item->category,
985	            'quantity'         => $qty,
986	            'unit_price'       => $unitPrice,
987	            'total_price'      => $totalPrice,
988	            'discount_amount'  => $discAmt,
989	            'discount_percent' => $discPc,
990	            'net_price'        => $netPrice,
991	            'notes'            => $data['notes'] ?? $item->notes,
992	        ]);
993	
994	        $this->recalculateInvoice($invoice);
995	
996	        return $item->fresh();
997	    }
