1234	    private function recalculateInvoice(BillingInvoice $invoice): void
1235	    {
1236	        $invoice->refresh();
1237	        // subtotal = gross (sum total_price) — net dihitung dari sum(net_price) yang sudah memperhitungkan diskon per-item.
1238	        $subtotal     = (float) $invoice->items()->sum('total_price');
1239	        $itemNet      = (float) $invoice->items()->sum('net_price');
1240	        $globalDisc   = (float) $invoice->discount;
1241	        $globalDiscPc = (float) ($invoice->discount_percent ?? 0);
1242	
1243	        // Bila discount_percent terisi, hitung ulang nominal global dari net item.
1244	        if ($globalDiscPc > 0) {
1245	            $globalDisc = round($itemNet * $globalDiscPc / 100, 2);
1246	            $invoice->update(['discount' => $globalDisc]);
1247	        }
1248	
1249	        $total = max(0, $itemNet - $globalDisc + (float) $invoice->tax);
1250	
1251	        $invoice->update(['subtotal' => $subtotal, 'total' => $total]);
1252	    }
