1329	    /**
1330	     * Setelah invoice PAID dan visit pakai ASURANSI/PERUSAHAAN dengan verifikasi
1331	     * VERIFIED, otomatis buat draft klaim. Billing tidak perlu manual klik "Buat
1332	     * Klaim Baru" — checklist dokumen sudah di-prepopulate dari master TPA.
1333	     *
1334	     * Tidak melempar exception kalau gagal — kegagalan auto-draft tidak boleh
1335	     * membatalkan transaksi pembayaran. Billing bisa selalu buat draft manual.
1336	     */
1337	    private function maybeCreateInsuranceClaimDraft(BillingInvoice $invoice): void
1338	    {
1339	        try {
1340	            $visit = $invoice->visit;
1341	            if (! $visit) return;
1342	
1343	            if (! in_array($visit->guarantor_type, ['ASURANSI', 'PERUSAHAAN'], true)) return;
1344	            if ($visit->insurance_verification_status !== 'VERIFIED') return;
1345	            if (! $visit->insurer_id) return;
1346	
1347	            // Hindari duplikat — kalau sudah ada klaim untuk invoice ini, skip.
1348	            $exists = \App\Models\InsuranceClaim::where('billing_invoice_id', $invoice->id)->exists();
1349	            if ($exists) return;
1350	
1351	            // Klaim ke TPA = porsi yang ditanggung asuransi (covered_amount). Jika admin
1352	            // belum menentukan cover, fallback ke seluruh nilai invoice (billing sesuaikan
1353	            // saat submit). Sisa = tanggungan pasien.
1354	            $claimAmount = (float) $invoice->covered_amount > 0
1355	                ? (float) $invoice->covered_amount
1356	                : (float) $invoice->total;
1357	            $patientResp = max(0, (float) $invoice->total - $claimAmount);
1358	
1359	            $this->asuransiService->createDraftKlaim([
1360	                'visit_id'               => $visit->id,
1361	                'insurer_id'             => $visit->insurer_id,
1362	                'billing_invoice_id'     => $invoice->id,
1363	                'claim_amount'           => $claimAmount,
1364	                'patient_responsibility' => $patientResp,
1365	                'source'                 => 'auto_after_payment',
1366	            ]);
1367	        } catch (\Throwable $e) {
1368	            // Log tapi jangan lempar — payment sudah committed.
1369	            $this->log(
1370	                auth('api')->id(),
1371	                'AUTO_DRAFT_CLAIM_FAILED',
1372	                BillingInvoice::class,
1373	                $invoice->id,
1374	                $e->getMessage()
1375	            );
1376	        }
1377	    }
